use std::cmp::{min,max};
//const INF: i32 = 0x3f3f3f3f;

struct Scanner {
    buffer: std::collections::VecDeque<String>
}

impl Scanner {
    fn new() -> Scanner {
        Scanner {
            buffer: std::collections::VecDeque::new()
        }
    }

    fn next<T: std::str::FromStr>(&mut self) -> T {
        while self.buffer.is_empty() {
            let mut input = String::new();
            std::io::stdin().read_line(&mut input).ok();
            self.buffer = input.split_whitespace()
                .map(ToString::to_string).collect();
        }
        let front = self.buffer.pop_front().unwrap();
        front.parse::<T>().ok().unwrap()
    }
}

fn solution() {
    let mut scanner = Scanner::new();
    let mut s: String = scanner.next();
    let n = s.len();
    let mut ans = 0;
    let mut current = 1;
    for i in 0..n {
        let d = s.chars().next().unwrap().to_digit(10).unwrap() as usize;
        let x = std::cmp::max(d as i32 - 1, 1) as usize;
        ans = std::cmp::max(ans, current * x * 9_usize.pow((n - i - 1) as u32));
        current *= d;
        s = s[1..].to_string();
    }
    ans = std::cmp::max(ans, current);
    println!("{}", ans);
}

fn main() {
    std::thread::Builder::new().stack_size(50 << 20)
        .spawn(solution).unwrap().join().unwrap();
}
